div.script:

        document.addEventListener("DOMContentLoaded", function () {

          const jsonHolder = document.getElementById("cube_json_data");
          if (!jsonHolder) return;

          let images = JSON.parse(jsonHolder.dataset.json || "[]");
          const cube = document.getElementById("multiCube");
          if (!cube || !images.length) return;

          const faces = cube.querySelectorAll(".cube-face");
          let index = 0;
          let rotation = 0;

          function updateFaces() {
    let shuffled = [...images].sort(() => Math.random() - 0.5);

    faces.forEach((face, i) => {
        const data = shuffled[i % shuffled.length];
        face.style.backgroundImage = "url('" + data.url + "')";
        face.innerHTML = "<span class='cube-title'>" + (data.event_name || "") + "</span>";
    });
}

          updateFaces();

          function rotateCube(dir) {
            rotation -= dir * 90;
            cube.style.transform = "rotateY(" + rotation + "deg)";
            index = (index + dir + images.length) % images.length;
            setTimeout(updateFaces, 600);
          }

          document.querySelector(".cube-next").onclick = () => rotateCube(1);
          document.querySelector(".cube-prev").onclick = () => rotateCube(-1);

          let auto = setInterval(() => rotateCube(1), 5000);
          cube.onmouseenter = () => clearInterval(auto);
          cube.onmouseleave = () => auto = setInterval(() => rotateCube(1), 5000);

        });
